const rawMaterials = $("Fetch Raw Materials").all();
const packagingMaterials = $("Fetch Packaging Material").all();
const batches = $("Fetch Batches").all();
const finalProducts = $("Fetch Final Products").all();
const suppliers = $("Fetch Suppliers").all();
const facilities = $("Fetch Facilities").all();

const data = {
  rawMaterials: $("Fetch Raw Materials").all().length,
  packagingMaterials: $("Fetch Packaging Material").all().length,
  batches: $("Fetch Batches").all().length,
  finalProducts: $("Fetch Final Products").all().length,
  suppliers: $("Fetch Suppliers").all().length,
  facilities: $("Fetch Facilities").all().length,
};

console.log(data)

const result = Object.entries(data).reduce(
  (max, [key, value]) =>
    value > max.length
      ? { name: key, length: value }
      : max,
  { name: null, length: 0 }
);

console.log(result);

let outputs = [];

for (let index = 0; index < result.length; index++) {
  const rawMaterial = data.rawMaterials > index ? rawMaterials[index] : null;
  const packagingMaterial = data.packagingMaterials > index ? packagingMaterials[index] : null;
  const batch = data.batches > index ? batches[index] : null;
  const finalProduct = data.finalProducts > index ? finalProducts[index] : null;
  const supplier = data.suppliers > index ? suppliers[index] : null;
  const facility = data.facilities > index ? facilities[index] : null;
  outputs.push({
    "Raw Materials": rawMaterial?.json?.name ?? "",
    "Raw Material ID" : rawMaterial?.json?.id ?? "",
    "Packaging Materials": packagingMaterial?.json?.name ?? "",
    "Packaging Material ID": packagingMaterial?.json?.id ?? "",
    "Batches": batch?.json?.name ?? "",
    "Batch ID": batch?.json?.id ?? "",
    "Final Products": finalProduct?.json?.name ?? "",
    "Final Product ID": finalProduct?.json?.id ?? "",
    "Suppliers": supplier?.json?.name ?? "",
    "Supplier ID": supplier?.json?.id ?? "",
    "Facility": facility?.json?.name ?? "",
    "Facility ID": facility?.json?.id ?? "",
  });
}

console.log(outputs);

return outputs.map(e=> {
  return { json: e }
});
